let chatHistory = [];
let chatThreadId = null;
let chatUserHandle = 'adam';
let oldestMessageId = null;
let loadingOlderMessages = false;
let chatHistoryExhausted = false;
const CHAT_GREETING = "Hey Adam 👋 — what's on your mind today?";
const CHAT_PAGE_SIZE = 80;

function mapDbRole(role) {
  if (role === 'user') return 'user';
  if (role === 'assistant') return 'assistant';
  return 'ambient';
}

function renderMessageEl(role, content, msgId) {
  const msgEl = document.createElement('div');
  msgEl.classList.add('msg', role);
  if (msgId) msgEl.dataset.msgId = String(msgId);
  msgEl.textContent = content;
  return msgEl;
}

function addMessage(role, content, { prepend = false, scroll = true, persistHistory = true, msgId = null } = {}) {
  const msgEl = renderMessageEl(role, content, msgId);
  if (prepend) {
    chatMessages.insertBefore(msgEl, chatMessages.firstChild);
  } else {
    chatMessages.appendChild(msgEl);
    if (scroll) chatMessages.scrollTop = chatMessages.scrollHeight;
  }
  if (persistHistory) chatHistory.push({ role, content });
}

async function resolveChatUser() {
  try {
    const r = await API('/api/v1/lifeos/auth/me');
    if (!r.ok) return;
    const d = await r.json();
    if (d.user?.user_handle) chatUserHandle = d.user.user_handle;
    else if (d.handle) chatUserHandle = d.handle;
  } catch {}
}

async function ensureDefaultChatThread() {
  const r = await API(`/api/v1/lifeos/chat/threads/default?user=${encodeURIComponent(chatUserHandle)}`);
  if (!r.ok) return false;
  const d = await r.json();
  if (!d.ok || !d.thread?.id) return false;
  chatThreadId = d.thread.id;
  return true;
}

async function fetchChatMessages(before = null) {
  if (!chatThreadId) return [];
  let url = `/api/v1/lifeos/chat/threads/${chatThreadId}/messages?user=${encodeURIComponent(chatUserHandle)}&limit=${CHAT_PAGE_SIZE}`;
  if (before) url += `&before=${before}`;
  const r = await API(url);
  if (!r.ok) return [];
  const d = await r.json();
  return d.ok && Array.isArray(d.messages) ? d.messages : [];
}

function showChatGreeting() {
  chatMessages.innerHTML = '';
  chatHistory = [];
  addMessage('assistant', CHAT_GREETING);
}

async function loadOlderChatMessages() {
  if (loadingOlderMessages || chatHistoryExhausted || !oldestMessageId || !chatThreadId) return;
  loadingOlderMessages = true;
  const hint = document.createElement('div');
  hint.className = 'chat-load-older';
  hint.textContent = 'Loading earlier messages…';
  chatMessages.insertBefore(hint, chatMessages.firstChild);
  const prevHeight = chatMessages.scrollHeight;
  try {
    const older = await fetchChatMessages(oldestMessageId);
    hint.remove();
    if (!older.length) {
      chatHistoryExhausted = true;
      return;
    }
    if (older.length < CHAT_PAGE_SIZE) chatHistoryExhausted = true;
    oldestMessageId = older[0]?.id || oldestMessageId;
    for (const m of older) {
      const uiRole = mapDbRole(m.role);
      chatMessages.insertBefore(renderMessageEl(uiRole, m.content, m.id), chatMessages.firstChild);
      chatHistory.unshift({ role: uiRole, content: m.content });
    }
    chatMessages.scrollTop = chatMessages.scrollHeight - prevHeight;
  } catch (e) {
    hint.remove();
    console.error('Failed to load older chat messages:', e);
  } finally {
    loadingOlderMessages = false;
  }
}

async function initChatHistory() {
  try {
    await resolveChatUser();
    const hasThread = await ensureDefaultChatThread();
    if (!hasThread) {
      showChatGreeting();
      return;
    }
    const msgs = await fetchChatMessages();
    if (!msgs.length) {
      showChatGreeting();
      return;
    }
    chatMessages.innerHTML = '';
    chatHistory = [];
    oldestMessageId = msgs[0]?.id || null;
    if (msgs.length < CHAT_PAGE_SIZE) chatHistoryExhausted = true;
    for (const m of msgs) {
      addMessage(mapDbRole(m.role), m.content, { scroll: false, msgId: m.id });
    }
    chatMessages.scrollTop = chatMessages.scrollHeight;
  } catch (e) {
    console.error('Failed to load chat history:', e);
    showChatGreeting();
  }
}

chatMessages.addEventListener('scroll', () => {
  if (chatMessages.scrollTop <= 64) loadOlderChatMessages();
});

