const luminState = {
  open: false,
  threadId: null,
  sending: false,
  dock: 'right',
  pinned: false,
  minimized: false,
};

const LUMIN_DOCK_KEY = 'lifeos_lumin_dock_position';
const LUMIN_PIN_KEY = 'lifeos_lumin_dock_pinned';
const LUMIN_MIN_KEY = 'lifeos_lumin_dock_minimized';

function initLuminDock() {
  const drawer = document.getElementById('lumin-drawer');
  if (!drawer) return;
  luminState.dock = localStorage.getItem(LUMIN_DOCK_KEY) || 'right';
  if (!['right', 'top', 'bottom'].includes(luminState.dock)) luminState.dock = 'right';
  luminState.pinned = localStorage.getItem(LUMIN_PIN_KEY) === 'true';
  luminState.minimized = localStorage.getItem(LUMIN_MIN_KEY) === 'true';
  applyLuminDockUi();
  if (luminState.pinned) openLuminDrawer();
}

function applyLuminDockUi() {
  const drawer = document.getElementById('lumin-drawer');
  if (!drawer) return;
  drawer.classList.remove('dock-right', 'dock-top', 'dock-bottom', 'pinned', 'minimized');
  drawer.classList.add(`dock-${luminState.dock}`);
  if (luminState.pinned) drawer.classList.add('pinned');
  if (luminState.minimized) drawer.classList.add('minimized');
  document.querySelectorAll('.lumin-dock-btn[data-dock]').forEach((btn) => {
    btn.classList.toggle('active', btn.dataset.dock === luminState.dock);
  });
  const pinBtn = document.getElementById('lumin-pin-btn');
  if (pinBtn) {
    pinBtn.classList.toggle('active', luminState.pinned);
    pinBtn.textContent = luminState.pinned ? 'Pinned' : 'Pin';
  }
  const minBtn = document.getElementById('lumin-min-btn');
  if (minBtn) minBtn.textContent = luminState.minimized ? 'Expand' : 'Min';
  const backdrop = document.getElementById('lumin-backdrop');
  if (backdrop && luminState.open && luminState.pinned) backdrop.classList.remove('open');
}

function setLuminDock(position) {
  if (!['right', 'top', 'bottom'].includes(position)) return;
  luminState.dock = position;
  localStorage.setItem(LUMIN_DOCK_KEY, position);
  applyLuminDockUi();
}

function toggleLuminPin() {
  luminState.pinned = !luminState.pinned;
  localStorage.setItem(LUMIN_PIN_KEY, luminState.pinned ? 'true' : 'false');
  if (luminState.pinned && !luminState.open) openLuminDrawer();
  applyLuminDockUi();
}

function toggleLuminMinimize() {
  luminState.minimized = !luminState.minimized;
  localStorage.setItem(LUMIN_MIN_KEY, luminState.minimized ? 'true' : 'false');
  applyLuminDockUi();
}

function toggleLuminDrawer() {
  if (luminState.open && !luminState.pinned) closeLuminDrawer();
  else openLuminDrawer();
}

