  if (matchesAny(violations, ['roadmap', 'FUTURE', 'BUILDER_SIMULATION', 'machine:', 'post_arc'])) {
    repairs.push(repairRoadmapPhases(missionFolder));
    repairs.push(refreshPostArcReceipts(missionFolder));
