function runPhaseWithRepair({
  phaseName,
  missionFolder,
  cookingBudget,
  totalAttemptsRef,
  loopReceipt,
  runFn,
}) {
  let lastResult = null;
  let phaseAttempts = 0;

  while (totalAttemptsRef.count < cookingBudget) {
    totalAttemptsRef.count += 1;
    phaseAttempts += 1;
    lastResult = runFn({ attempt: phaseAttempts, force: phaseAttempts > 1 });
    const record = {
      phase: phaseName,
      attempt: phaseAttempts,
      cooking_spent: totalAttemptsRef.count,
      cooking_remaining: cookingBudget - totalAttemptsRef.count,
      at: new Date().toISOString(),
      ok: Boolean(lastResult?.ok),
    };

    if (lastResult?.ok) {
      loopReceipt.attempts.push(record);
      loopReceipt.phases[phaseName] = { ok: true, attempts: phaseAttempts };
      return lastResult;
    }

    const repair = repairForStage(missionFolder, phaseName, lastResult);
    record.repair = repair;
    record.violations = repair.violations;
    loopReceipt.attempts.push(record);
    loopReceipt.repairs.push(repair);

    if (totalAttemptsRef.count >= cookingBudget) {
      break;
    }
  }

  const stopped = 'cooking_budget_exhausted';
  loopReceipt.phases[phaseName] = {
    ok: false,
    attempts: phaseAttempts,
    stopped,
    stoppage_is_failure: false,
    stoppage_acceptable: true,
  };
  loopReceipt.stoppage = {
    reason: stopped,
    phase: phaseName,
    cooking_spent: totalAttemptsRef.count,
    cooking_budget: cookingBudget,
    acceptable: true,
    lesson: 'Only acceptable halt — cooking budget exhausted while phase still failing. Increase budget or fix root blocker.',
  };
  return lastResult;
}

function finalizeLoopReceipt(loopReceipt, { started, cookingBudget, totalAttemptsRef, ok }) {
  loopReceipt.finished_at = new Date().toISOString();
  loopReceipt.ok = ok;
  loopReceipt.total_attempts = totalAttemptsRef.count;
  loopReceipt.cooking_budget = cookingBudget;
  loopReceipt.cooking_remaining = Math.max(0, cookingBudget - totalAttemptsRef.count);
  loopReceipt.latency_ms = Date.now() - started;
  if (!loopReceipt.stoppage && !ok) {
    loopReceipt.stoppage = {
      reason: 'unexpected_stoppage',
      acceptable: false,
      stoppage_is_failure: true,
      lesson: 'System stopped before PASS without exhausting cooking budget — this is a defect.',
    };
  }
}

/**
 * Never-stop foundation loop — repair on FAIL, retry until each phase PASS.
 * Only valid stop: cooking budget exhausted.
 */
export function runFoundationPipelineLoop(missionIdOrPath, options = {}) {
  const cookingBudget = options.cookingBudget
    ?? options.maxTotalAttempts
    ?? 128;
  const force = options.force ?? false;
  const dryRun = options.dryRun ?? false;

  const folder = resolveMissionFolder(missionIdOrPath);
  if (!folder) {
    return {
      ok: false,
      error: 'mission_not_found',
      stoppage: { reason: 'mission_not_found', acceptable: false, stoppage_is_failure: true },
    };
  }

  const missionId = path.basename(folder);
  const started = Date.now();
  const totalAttemptsRef = { count: 0 };
  const loopReceipt = {
    schema: 'foundation_loop_receipt_v2',
    mission_id: missionId,
    mode: 'never_stop_until_pass_or_budget',
    started_at: new Date().toISOString(),
    cooking_budget: cookingBudget,
    attempts: [],
    phases: {},
    repairs: [],
  };

  const development = runPhaseWithRepair({
    phaseName: 'development',
    missionFolder: folder,
    cookingBudget,
    totalAttemptsRef,
    loopReceipt,
    runFn: ({ force: retryForce }) => runDevelopmentStage(missionId, { force: force || retryForce }),
  });

  if (!development?.ok) {
    finalizeLoopReceipt(loopReceipt, { started, cookingBudget, totalAttemptsRef, ok: false });
    writeJson(path.join(folder, 'receipts/FOUNDATION_LOOP_RECEIPT.json'), loopReceipt);
    return { ok: false, loopReceipt, lastStage: 'development' };
  }

  const corridor = runPhaseWithRepair({
    phaseName: 'corridor',
    missionFolder: folder,
    cookingBudget,
    totalAttemptsRef,
    loopReceipt,
    runFn: () => {
      const translate = runCorridorStage(missionId, { dryRun });
      return { ok: translate.ok, translate };
    },
  });

  if (!corridor?.ok) {
    finalizeLoopReceipt(loopReceipt, { started, cookingBudget, totalAttemptsRef, ok: false });
    writeJson(path.join(folder, 'receipts/FOUNDATION_LOOP_RECEIPT.json'), loopReceipt);
    return { ok: false, loopReceipt, lastStage: 'corridor' };
  }

  if (!dryRun) {
    const builderEntry = runPhaseWithRepair({
      phaseName: 'builder_entry',
      missionFolder: folder,
      cookingBudget,
      totalAttemptsRef,
      loopReceipt,
      runFn: () => {
        const gate = evaluateBuilderEntryGate(folder);
        return { ok: gate.pass, ...gate };
      },
    });

    if (!builderEntry?.ok) {
      finalizeLoopReceipt(loopReceipt, { started, cookingBudget, totalAttemptsRef, ok: false });
      writeJson(path.join(folder, 'receipts/FOUNDATION_LOOP_RECEIPT.json'), loopReceipt);
      return { ok: false, loopReceipt, lastStage: 'builder_entry' };
    }

    const builder = runPhaseWithRepair({
      phaseName: 'builder',
      missionFolder: folder,
      cookingBudget,
      totalAttemptsRef,
      loopReceipt,
      runFn: () => runBuilderStage(missionId),
    });

    if (!builder?.ok) {
      finalizeLoopReceipt(loopReceipt, { started, cookingBudget, totalAttemptsRef, ok: false });
      writeJson(path.join(folder, 'receipts/FOUNDATION_LOOP_RECEIPT.json'), loopReceipt);
      return { ok: false, loopReceipt, lastStage: 'builder' };
    }
  }

  const finalResult = runPhaseWithRepair({
    phaseName: 'final_gate',
    missionFolder: folder,
    cookingBudget,
    totalAttemptsRef,
    loopReceipt,
    runFn: () => {
      const bp = loadMissionJson(folder, 'BLUEPRINT.json');
      const finalGate = evaluatePointBGate(folder, { blueprint: bp });
      const doctrine = evaluateMissionDoctrine(folder, { blueprint: bp });
      const violations = [...(finalGate.violations || []), ...(doctrine.violations || [])];
      const ok = finalGate.machine_path_complete && doctrine.pass;
      return { ok, finalGate, doctrine, violations };
    },
  });

  if (finalResult?.ok) {
    scoreRealityAgainstSimulations(folder);
    loopReceipt.phases.scoreboard = writeResultScoreboard(folder);
    loopReceipt.phases.release_gate = evaluateReleasePassGate(folder);
  } else {
    loopReceipt.phases.final_gate_detail = finalResult?.finalGate;
    loopReceipt.phases.doctrine_detail = finalResult?.doctrine;
  }

  const pipelineOk = Boolean(finalResult?.ok);
  finalizeLoopReceipt(loopReceipt, { started, cookingBudget, totalAttemptsRef, ok: pipelineOk });
  loopReceipt.awaiting_alpha = pipelineOk && !finalResult?.finalGate?.alpha_reached;

  writeJson(path.join(folder, 'receipts/FOUNDATION_LOOP_RECEIPT.json'), loopReceipt);
  writeJson(path.join(folder, 'receipts/FOUNDATION_PIPELINE_REPORT.json'), {
    schema: 'foundation_pipeline_report_v1',
    mission_id: missionId,
    at: new Date().toISOString(),
    ok: pipelineOk,
    loop_mode: true,
    loop_receipt: 'receipts/FOUNDATION_LOOP_RECEIPT.json',
    stages: loopReceipt.phases,
    stoppage: loopReceipt.stoppage || null,
    awaiting_alpha: loopReceipt.awaiting_alpha,
  });

  appendMissionLedger({
    mission_id: missionId,
    event: pipelineOk ? 'foundation_loop_complete' : 'foundation_loop_budget_exhausted',
    runner: 'run-foundation.js',
    latency_ms: loopReceipt.latency_ms,
    verdict: pipelineOk ? 'PASS' : 'COOKING_BUDGET_EXHAUSTED',
    total_attempts: totalAttemptsRef.count,
    cooking_budget: cookingBudget,
  });

  return { ok: pipelineOk, loopReceipt, awaiting_alpha: loopReceipt.awaiting_alpha };
}

