export function runFoundationPipelineLoop(missionIdOrPath, options = {}) {
  const cookingBudget = options.cookingBudget
    ?? options.maxTotalAttempts
    ?? 128;
  const force = options.force ?? false;
  const dryRun = options.dryRun ?? false;

  const folder = resolveMissionFolder(missionIdOrPath);
  if (!folder) {
    return {
      ok: false,
      error: 'mission_not_found',
      stoppage: { reason: 'mission_not_found', acceptable: false, stoppage_is_failure: true },
    };
  }

  const missionId = path.basename(folder);
  const started = Date.now();
  const totalAttemptsRef = { count: 0 };
  const loopReceipt = {
    schema: 'foundation_loop_receipt_v2',
    mission_id: missionId,
    mode: 'never_stop_until_pass_or_budget',
    started_at: new Date().toISOString(),
    cooking_budget: cookingBudget,
    attempts: [],
    phases: {},
    repairs: [],
  };

  const development = runPhaseWithRepair({
    phaseName: 'development',
    missionFolder: folder,
    cookingBudget,
    totalAttemptsRef,
    loopReceipt,
    runFn: ({ force: retryForce }) => runDevelopmentStage(missionId, { force: force || retryForce }),
  });

  if (!development?.ok) {
    finalizeLoopReceipt(loopReceipt, { started, cookingBudget, totalAttemptsRef, ok: false });
    writeJson(path.join(folder, 'receipts/FOUNDATION_LOOP_RECEIPT.json'), loopReceipt);
    return { ok: false, loopReceipt, lastStage: 'development' };
  }

  const corridor = runPhaseWithRepair({
    phaseName: 'corridor',
    missionFolder: folder,
    cookingBudget,
    totalAttemptsRef,
    loopReceipt,
    runFn: () => {
      const translate = runCorridorStage(missionId, { dryRun });
      return { ok: translate.ok, translate };
    },
  });

  if (!corridor?.ok) {
    finalizeLoopReceipt(loopReceipt, { started, cookingBudget, totalAttemptsRef, ok: false });
    writeJson(path.join(folder, 'receipts/FOUNDATION_LOOP_RECEIPT.json'), loopReceipt);
    return { ok: false, loopReceipt, lastStage: 'corridor' };
  }

  if (!dryRun) {
    const builderEntry = runPhaseWithRepair({
      phaseName: 'builder_entry',
      missionFolder: folder,
      cookingBudget,
      totalAttemptsRef,
      loopReceipt,
      runFn: () => {
        const gate = evaluateBuilderEntryGate(folder);
        return { ok: gate.pass, ...gate };
      },
    });

    if (!builderEntry?.ok) {
      finalizeLoopReceipt(loopReceipt, { started, cookingBudget, totalAttemptsRef, ok: false });
      writeJson(path.join(folder, 'receipts/FOUNDATION_LOOP_RECEIPT.json'), loopReceipt);
      return { ok: false, loopReceipt, lastStage: 'builder_entry' };
    }

