/**
 * Founder build success gate — PASS requires commit + deploy sync + live CSS proof.
 * Wires existing deploy SHA probe, Railway redeploy, and overlay fetch paths.
 *
 * @ssot docs/projects/BUILDEROS_ALPHA_BLUEPRINT.md
 */
import fs from 'node:fs';
import path from 'node:path';
import {
  APP_HTML_TARGET,
  ASSISTANT_BUBBLE_CSS_TARGET,
  DASHBOARD_HTML_TARGET,
  parseAssistantBubbleColors,
} from './founder-css-patch.js';
import { isCssOnlyUiFeedback } from './builder-instruction-target.js';

export const FOUNDER_CSS_COMMIT_FILES = [
  ASSISTANT_BUBBLE_CSS_TARGET,
  DASHBOARD_HTML_TARGET,
  APP_HTML_TARGET,
];

export const FOUNDER_BUILD_TOOL_INVENTORY = {
  entry: 'POST /api/v1/lifeos/builderos/command-control/founder-interface/message',
  routing: [
    'routes/lifeos-builderos-command-control-routes.js — founder build + auth + persist',
    'services/builder-instruction-target.js — target_file infer, css-only heuristic, keep-trying resume',
  ],
  execution: [
    'services/founder-build-self-repair.js — never-stop loop (5 attempts)',
    'services/founder-css-patch.js — mechanical CSS (inline + theme, no HTML rewrite)',
    'routes/lifeos-council-builder-routes.js — POST /builder/task + /builder/execute + overlay shrink block',
  ],
  truth: [
    'services/lifeos-execution-truth.js — PASS/FAIL gate, autopsy, stub/scope detection',
    'services/founder-build-success-gate.js — deploy sync + live overlay CSS verification',
    'services/builder-outcome-verifier.js — governed-loop outcome parity (git show)',
  ],
  deploy: [
    'GET /api/v1/lifeos/builder/ready — deploy_commit_sha',
    'POST /api/v1/railway/deploy — redeploy after commit',
    'POST /api/v1/railway/managed-env/build-from-latest — fresh image from main',
    'scripts/system-railway-redeploy.mjs — operator redeploy + health poll',
    'services/lifeos-system-agent.js — answerDeployVsCommit',
  ],
  cache: [
    'public/overlay/sw.js — service worker CACHE_NAME bump on CSS patch',
    'founder-css-patch bumpThemeOverridesHref — ?v= cache bust on theme link',
  ],
  repair: [
    'services/self-repair-executor.js + routes/self-repair-executor-routes.js',
    'factory-staging/factory-core/arc/foundation/obstacle-lesson-loop.js',
  ],
};

const DEFAULT_DEPLOY_WAIT_MS = Number(process.env.FOUNDER_DEPLOY_WAIT_MS || '180000');
const DEFAULT_DEPLOY_POLL_MS = Number(process.env.FOUNDER_DEPLOY_POLL_MS || '5000');

function normalizeSha(sha) {
  return String(sha || '').trim().slice(0, 12);
}

function cssTokenPresent(content, token) {
  const text = String(content || '').toLowerCase();
  const needle = String(token || '').toLowerCase();
  return needle.length > 0 && text.includes(needle);
}

export async function fetchDeployCommitSha(baseUrl, commandKey) {
  const base = String(baseUrl || '').replace(/\/$/, '');
  if (!base || !commandKey) return null;
  try {
    const res = await fetch(`${base}/api/v1/lifeos/builder/ready`, {
      headers: { 'x-command-key': commandKey },
    });
    if (!res.ok) return null;
    const data = await res.json();
    return data?.codegen?.deploy_commit_sha || data?.builder?.deploy_commit_sha || null;
  } catch {
    return null;
  }
}

export async function waitForDeployMatchingCommit({
  baseUrl,
  commandKey,
  commitSha,
  maxWaitMs = DEFAULT_DEPLOY_WAIT_MS,
  pollMs = DEFAULT_DEPLOY_POLL_MS,
} = {}) {
  const expected = normalizeSha(commitSha);
  if (!expected) {
    return { ok: false, code: 'COMMIT_NO_SHA', blocker: 'Cannot verify deploy without commit SHA.' };
  }
  const deadline = Date.now() + maxWaitMs;
  let lastDeploySha = null;
  while (Date.now() < deadline) {
    lastDeploySha = await fetchDeployCommitSha(baseUrl, commandKey);
    const live = normalizeSha(lastDeploySha);
    if (live && (live.startsWith(expected.slice(0, 7)) || expected.startsWith(live.slice(0, 7)))) {
      return { ok: true, deploy_sha: lastDeploySha, commit_sha: commitSha, waited_ms: maxWaitMs - (deadline - Date.now()) };
    }
    await new Promise((r) => setTimeout(r, pollMs));
  }
  return {
    ok: false,
    code: 'DEPLOY_NOT_SYNCED',
    blocker: `Deploy SHA (${normalizeSha(lastDeploySha) || 'unknown'}) does not match commit ${expected} after ${Math.round(maxWaitMs / 1000)}s.`,
    deploy_sha: lastDeploySha,
    commit_sha: commitSha,
  };
}

export async function triggerRailwayRedeploy({ baseUrl, commandKey }) {
  const base = String(baseUrl || '').replace(/\/$/, '');
  if (!base || !commandKey) {
    return { ok: false, error: 'missing_base_or_key' };
  }
  for (const url of [
    `${base}/api/v1/railway/deploy`,
    `${base}/api/v1/railway/managed-env/build-from-latest`,
  ]) {
    try {
      const res = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'x-command-key': commandKey },
        body: '{}',
      });
      const json = await res.json().catch(() => ({}));
      if (res.ok && json?.ok !== false) {
        return { ok: true, path: url, json };
      }
      if (res.status === 410 && json?.error === 'LEGACY_RAILWAY_CONTROL_DISABLED') continue;
    } catch {
      /* try next path */
    }
  }
  return { ok: false, error: 'redeploy_paths_exhausted' };
}

export function verifyInlineCssInHtml(html, colors) {
  const text = String(html || '');
  const hasAssistantRule = /\.msg\.assistant|\.lumin-msg\.assistant/.test(text);
  const hasBg = cssTokenPresent(text, colors.background);
  const hasColor = cssTokenPresent(text, colors.color);
  if (!hasAssistantRule) {
    return { ok: false, reason: 'assistant_selector_missing' };
  }
  if (!hasBg || !hasColor) {
    return { ok: false, reason: 'color_tokens_missing', hasBg, hasColor };
  }
  return { ok: true };
}

export function verifyCssPatchLocal({ patchResult }) {
  if (!patchResult?.ok || !Array.isArray(patchResult.files)) {
    return { ok: false, code: 'PATCH_INVALID', blocker: 'Mechanical CSS patch did not produce file outputs.' };
  }
  const colors = patchResult.colors || parseAssistantBubbleColors('yellow black text');
  const byTarget = Object.fromEntries(patchResult.files.map((f) => [f.target_file, f.output]));
  const missing = FOUNDER_CSS_COMMIT_FILES.filter((f) => !byTarget[f]);
  if (missing.length) {
    return {
      ok: false,
      code: 'SCOPE_INCOMPLETE',
      blocker: `CSS patch missing files: ${missing.join(', ')}`,
      missing,
    };
  }
  const dashCheck = verifyInlineCssInHtml(byTarget[DASHBOARD_HTML_TARGET], colors);
  if (!dashCheck.ok) {
    return {
      ok: false,
      code: 'LOCAL_CSS_MISSING',
      blocker: `Dashboard inline CSS failed local check: ${dashCheck.reason}`,
      surface: DASHBOARD_HTML_TARGET,
    };
  }
  const appCheck = verifyInlineCssInHtml(byTarget[APP_HTML_TARGET], colors);
  if (!appCheck.ok) {
    return {
      ok: false,
      code: 'LOCAL_CSS_MISSING',
      blocker: `App shell inline CSS failed local check: ${appCheck.reason}`,
      surface: APP_HTML_TARGET,
    };
  }
  const themeText = byTarget[ASSISTANT_BUBBLE_CSS_TARGET];
  if (!cssTokenPresent(themeText, colors.background) || !/founder-assistant-bubble-style:start/.test(themeText)) {
    return {
      ok: false,
      code: 'LOCAL_CSS_MISSING',
      blocker: 'Theme overrides missing founder assistant bubble block.',
      surface: ASSISTANT_BUBBLE_CSS_TARGET,
    };
  }
  return { ok: true, code: 'LOCAL_CSS_VERIFIED', colors };
}

export async function fetchLiveOverlayHtml(baseUrl, overlayFile) {
  const base = String(baseUrl || '').replace(/\/$/, '');
  const rel = String(overlayFile || '').replace(/^public\/overlay\//, '');
  const url = `${base}/overlay/${rel}`;
  try {
    const res = await fetch(url, { headers: { 'Cache-Control': 'no-cache' } });
    if (!res.ok) return { ok: false, status: res.status, url };
    const text = await res.text();
    return { ok: true, status: res.status, url, text };
  } catch (err) {
    return { ok: false, url, error: err.message };
  }
}

export async function verifyCssPatchLive({ baseUrl, patchResult }) {
  const colors = patchResult?.colors || parseAssistantBubbleColors('yellow black text');
  const dash = await fetchLiveOverlayHtml(baseUrl, DASHBOARD_HTML_TARGET);
  if (!dash.ok) {
    return {
      ok: false,
      code: 'LIVE_FETCH_FAILED',
      blocker: `Could not fetch live ${DASHBOARD_HTML_TARGET}: HTTP ${dash.status || dash.error}`,
      url: dash.url,
    };
  }
  const dashCheck = verifyInlineCssInHtml(dash.text, colors);
  if (!dashCheck.ok) {
    return {
      ok: false,
      code: 'FOUNDER_VISUAL_NOT_VERIFIED',
      blocker: `Live dashboard missing expected CSS (${colors.background} / ${colors.color}) — ${dashCheck.reason}.`,
      surface: DASHBOARD_HTML_TARGET,
      url: dash.url,
    };
  }
  const app = await fetchLiveOverlayHtml(baseUrl, APP_HTML_TARGET);
  if (!app.ok) {
    return {
      ok: false,
      code: 'LIVE_FETCH_FAILED',
      blocker: `Could not fetch live ${APP_HTML_TARGET}: HTTP ${app.status || app.error}`,
      url: app.url,
    };
  }
  const appCheck = verifyInlineCssInHtml(app.text, colors);
  if (!appCheck.ok) {
    return {
      ok: false,
      code: 'FOUNDER_VISUAL_NOT_VERIFIED',
      blocker: `Live app shell missing expected CSS (${colors.background} / ${colors.color}) — ${appCheck.reason}.`,
      surface: APP_HTML_TARGET,
      url: app.url,
    };
  }
  return {
    ok: true,
    code: 'FOUNDER_VISUAL_VERIFIED',
    surfaces: [DASHBOARD_HTML_TARGET, APP_HTML_TARGET],
    colors,
  };
}

export function founderVerificationRequired(task, executionPath) {
  if (executionPath === 'founder_css_patch') return true;
  return isCssOnlyUiFeedback(task);
}

export async function runFounderSuccessGate({
  task,
  executionPath,
  patchResult,
  commitSha,
  baseUrl,
  commandKey,
  skipLive = false,
  skipDeployWait = false,
}) {
  if (!founderVerificationRequired(task, executionPath)) {
    return { ok: true, code: 'NOT_REQUIRED', skipped: true };
  }

  const local = verifyCssPatchLocal({ patchResult });
  if (!local.ok && patchResult) {
    return { ...local, stage: 'local' };
  }

  if (skipLive || process.env.FOUNDER_SKIP_LIVE_VERIFY === '1') {
    return {
      ok: false,
      code: 'FOUNDER_VISUAL_NOT_VERIFIED',
      blocker: 'Live founder verification is required for UI CSS PASS but was skipped (FOUNDER_SKIP_LIVE_VERIFY).',
      stage: 'live_skipped',
    };
  }

  if (!skipDeployWait && commitSha) {
    const deploy = await waitForDeployMatchingCommit({ baseUrl, commandKey, commitSha });
    if (!deploy.ok) {
      return { ...deploy, stage: 'deploy' };
    }
  }

  const live = await verifyCssPatchLive({ baseUrl, patchResult });
  return { ...live, stage: 'live' };
}

export function readRepoFileForPatch(root, relPath) {
  const abs = path.join(root, relPath);
  if (!fs.existsSync(abs)) return '';
  return fs.readFileSync(abs, 'utf8');
}

