async function pollFounderBuildJob(jobId, pollUrl) {
  const deadline = Date.now() + 300000;
  while (Date.now() < deadline) {
    const r = await API(pollUrl || `/api/v1/lifeos/builderos/command-control/founder-interface/build-job/${jobId}`);
    const d = await r.json();
    if (r.status === 202 || d.pass_fail === 'RUNNING') {
      await new Promise((resolve) => setTimeout(resolve, 2500));
      continue;
    }
    return { r, d };
  }
  return { r: { ok: false, status: 504 }, d: { pass_fail: 'FAIL', first_blocker: 'Build job timed out after 5 minutes.' } };
}
