}

async function pollFounderBuildJob(jobId, pollUrl) {
  const deadline = Date.now() + 300000;
  while (Date.now() < deadline) {
    const res = await fetch(pollUrl || `/api/v1/lifeos/builderos/command-control/founder-interface/build-job/${jobId}`, {
      credentials: 'same-origin',
      headers: await directSystemHeaders(),
    });
    const data = await res.json();
    if (res.status === 202 || data.pass_fail === 'RUNNING') {
      await new Promise((resolve) => setTimeout(resolve, 2500));
      continue;
    }
    return { res, data };
  }
  return { res: { ok: false, status: 504 }, data: { pass_fail: 'FAIL', first_blocker: 'Build job timed out after 5 minutes.' } };
}

