  testParseQuorumResponse();
  await testCfoApprovesAfterThreeSolo();
  await testCfoBlocksHumanRequired();
  console.log('founder-build-quorum-escalation tests: PASS');
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

