import { hasSynopsis, inferSynopsis, injectSynopsis, isInFileEnforceable } from './scripts/lib/file-synopsis.mjs';

const ROOT = process.cwd();
const GLOBS = [
  'services/builderos-*.js',
  'services/founder-*.js',
  'services/founder-build-*.js',
  'services/action-inbox.js',
