  'factory-staging/factory-core/**/*.js',
];

function walk(relDir, out = []) {
  const abs = path.join(ROOT, relDir);
  if (!fs.existsSync(abs)) return out;
  for (const ent of fs.readdirSync(abs, { withFileTypes: true })) {
    const rel = path.join(relDir, ent.name).replace(/\\/g, '/');
    if (ent.isDirectory()) walk(rel, out);
    else if (ent.isFile() && isInFileEnforceable(rel)) out.push(rel);
  }
  return out;
}

const files = new Set();
for (const g of GLOBS) {
  if (g.includes('**')) {
    const base = g.split('/**')[0];
    walk(base).forEach((f) => files.add(f));
  } else if (g.includes('*')) {
    const dir = path.dirname(g);
    const re = new RegExp('^' + g.replace(/\./g, '\\.').replace(/\*/g, '[^/]+') + '$');
    walk(dir || '.').filter((f) => re.test(f)).forEach((f) => files.add(f));
  } else if (fs.existsSync(path.join(ROOT, g))) {
    files.add(g);
  }
}

let fixed = 0;
let had = 0;
for (const rel of [...files].sort()) {
  const abs = path.join(ROOT, rel);
  let content = fs.readFileSync(abs, 'utf8');
  const ext = path.extname(rel);
  if (hasSynopsis(content, ext)) { had++; continue; }
  const synopsis = inferSynopsis(rel, content);
  const next = injectSynopsis(content, synopsis, ext);
  if (next !== content) {
    fs.writeFileSync(abs, next);
    fixed++;
  }
}
console.log(JSON.stringify({ scanned: files.size, already_had_synopsis: had, injected: fixed }, null, 2));
EOF

