/**
 * SYNOPSIS: Web research for obstacle lessons — how others solved similar blockers.
 * WIRED: point-b-navigator + obstacle-lesson-loop
 * @ssot docs/projects/AMENDMENT_04_AUTO_BUILDER.md
 */

import { createWebSearchService } from './web-search-service.js';

export function createObstacleWebResearch({ callAI, logger = console } = {}) {
  const search = createWebSearchService({
    BRAVE_SEARCH_API_KEY: process.env.BRAVE_SEARCH_API_KEY,
    PERPLEXITY_API_KEY: process.env.PERPLEXITY_API_KEY,
    callAI,
  });

  function buildQuery({ phase, violations = [], mission_id, kind }) {
    const blob = violations.slice(0, 5).join(' ').slice(0, 400);
    return [
      'software engineering pipeline obstacle fix',
      mission_id || '',
      phase || '',
      kind || '',
      blob,
      'concrete solution steps not generic advice',
    ].filter(Boolean).join(' ');
  }

  async function researchObstacle(context = {}) {
    const query = buildQuery(context);
    try {
      const result = await search.search(query, { count: 4 });
      const snippets = (result.results || [])
        .map((r) => ({ title: r.title, url: r.url, snippet: String(r.description || '').slice(0, 500) }))
        .filter((r) => r.snippet || r.url);
      return {
        ok: true,
        query,
        source: result.source || 'unknown',
        snippets,
        fix_hints: snippets.slice(0, 3).map((s) => s.snippet).filter(Boolean),
      };
    } catch (err) {
      logger.warn?.({ err: err.message }, '[OBSTACLE-WEB-RESEARCH] search failed');
      return { ok: false, query, error: err.message, snippets: [], fix_hints: [] };
    }
  }

  return { researchObstacle, buildQuery };
}

export async function researchObstacleBlocker(context, deps = {}) {
  const svc = createObstacleWebResearch(deps);
  return svc.researchObstacle(context);
}

/**
 * SYNOPSIS: Point B navigator — reads POINT_B_TARGET.json and returns next gate action.
 * WIRED: founder-interface/message default path + GET point-b/status + lifeos-app strip
 * @ssot docs/projects/AMENDMENT_04_AUTO_BUILDER.md
 */

import fs from 'node:fs';
import path from 'node:path';
import { spawn } from 'node:child_process';
import { fileURLToPath } from 'node:url';
import { loadPointBTarget, evaluatePointBTargetReached } from '../factory-staging/factory-core/arc/foundation/point-b-target.js';
import { evaluatePointBGate } from '../factory-staging/factory-core/arc/point-b-gate.js';
import { evaluateBuilderEntryGate } from '../factory-staging/factory-core/arc/foundation/builder-entry-gate.js';
import { founderStopActive } from '../factory-staging/factory-core/arc/gate-enforcement.js';
import { loadMissionJson } from '../factory-staging/factory-core/arc/mission-paths.js';
import { runFoundationPipelineForFounder } from './lifeos-mission-pipeline-executor.js';
import { researchObstacleBlocker } from './obstacle-web-research.js';

const REPO_ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const EXECUTE_MISSION = path.join(REPO_ROOT, 'builderos-reboot/scripts/execute-mission.mjs');

function loadJson(absPath, fallback = null) {
  if (!fs.existsSync(absPath)) return fallback;
  try {
    return JSON.parse(fs.readFileSync(absPath, 'utf8'));
  } catch {
    return fallback;
  }
}

function missionFolder(missionId, target) {
  const rel = target?.mission_folder || `builderos-reboot/MISSIONS/${missionId}`;
  return path.join(REPO_ROOT, rel);
}

function lastObstacle(folder) {
  const ledger = loadJson(path.join(folder, 'receipts/OBSTACLE_LESSON_LEDGER.json'), { obstacles: [] });
  const obstacles = ledger.obstacles || [];
  return obstacles.length ? obstacles[obstacles.length - 1] : null;
}

function estimateProgress({ gate, hasBlueprint, builderEntryPass, builderRunPass, acceptanceOk }) {
  if (gate.alpha_reached) return 100;
  if (gate.machine_path_complete) return 90;
  if (builderRunPass) return 75;
  if (hasBlueprint && builderEntryPass) return 55;
  if (gate.corridor?.pass) return 40;
  if (gate.handoff?.pass) return 25;
  return 10;
}

export function shouldRouteToPointBNavigator(text = '', {
  shouldDisplayOnly = false,
  isBuild = false,
  explicitExecute = false,
  isMissionIntent = false,
} = {}) {
  if (shouldDisplayOnly || isBuild || explicitExecute || isMissionIntent) return false;
  const t = String(text || '');
  if (isPureCounselQuestion(t)) return false;
  return true;
}

export function isPureCounselQuestion(text = '') {
  const t = String(text || '').trim();
  if (!/\?\s*$/.test(t)) return false;
  if (/\b(status|keep going|point b|continue|progress|execute|build|fix|change|lifere|mission)\b/i.test(t)) {
    return false;
  }
  return true;
}

export function isPointBStatusIntent(text = '') {
  return /\b(status|keep going|continue|point b|progress|what('s| is) next|advance|autopilot|never[- ]stop)\b/i.test(String(text || ''));
}

